CREATE PROCEDURE [dbo].[spProductUnitConversionUpdate] @UnitConversionId INT, @FromUnitId INT, @ToUnitId INT, @ConversionRate DECIMAL(18,6), @Description NVARCHAR(500), @IsActive BIT, @UpdatedByUserId INT AS BEGIN SET NOCOUNT ON; UPDATE [dbo].[ProductUnitConversion] SET FromUnitId=@FromUnitId, ToUnitId=@ToUnitId, ConversionRate=@ConversionRate, Description=ISNULL(@Description,N''), IsActive=@IsActive, UpdatedByUserId=NULLIF(@UpdatedByUserId,0), UpdatedDate=SYSUTCDATETIME() WHERE UnitConversionId=@UnitConversionId; END;
